import React, { useState } from 'react';
import { useForm } from 'react-hook-form';
import { yupResolver } from '@hookform/resolvers/yup';
import * as yup from 'yup';
import { Link, useNavigate } from 'react-router-dom';
import { FaUser, FaLock, FaEnvelope, FaPhone, FaMapMarkerAlt, FaCalendar } from 'react-icons/fa';
import { useAuth } from '../../hooks/useAuth';
import type { RegisterRequest } from '../../types/auth';
import LoadingSpinner from '../../components/common/LoadingSpinner';

const phoneRegExp = /^(\+91[\-\s]?)?[6789]\d{9}$/;

const registerSchema = yup.object().shape({
    name: yup.string().required('Full name is required'),
    email: yup.string().email('Please enter a valid email address').required('Email is required'),
    phone: yup.string().matches(phoneRegExp, 'Phone number must be a valid Indian number (+91 or 10 digits starting with 6-9)').required('Phone number is required'),
    password: yup.string()
        .required('Password is required')
        .min(8, 'Password must be at least 8 characters')
        .matches(/[a-z]/, 'Must contain at least one lowercase letter')
        .matches(/[A-Z]/, 'Must contain at least one uppercase letter')
        .matches(/[0-9]/, 'Must contain at least one number'),
    confirmPassword: yup.string()
        .oneOf([yup.ref('password')], 'Passwords must match')
        .required('Confirm Password is required'),
    role: yup.string().oneOf(['PATIENT', 'MEDICAL_OFFICER', 'TECHNICIAN']).required('Role is required'),
    // Conditional formatting based on role
    address: yup.string().when('role', {
        is: 'PATIENT',
        then: (schema) => schema.required('Address is required for patients'),
        otherwise: (schema) => schema.notRequired(),
    }),
    dateOfBirth: yup.string().when('role', {
        is: 'PATIENT',
        then: (schema) => schema.required('Date of Birth is required for patients'),
        otherwise: (schema) => schema.notRequired(),
    })
});

type RegisterFormInputs = yup.InferType<typeof registerSchema>;

const Register: React.FC = () => {
    const { register: registerUser } = useAuth();
    const navigate = useNavigate();
    const [isSubmitting, setIsSubmitting] = useState(false);

    const { register, handleSubmit, watch, formState: { errors } } = useForm<RegisterFormInputs>({
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        resolver: yupResolver(registerSchema) as any,
        defaultValues: {
            role: 'PATIENT'
        }
    });

    const selectedRole = watch('role');
    const passwordValue = watch('password') || '';

    // Calculate password strength (0-4)
    const calculateStrength = (pass: string) => {
        let score = 0;
        if (!pass) return score;
        if (pass.length >= 8) score += 1;
        if (/[A-Z]/.test(pass)) score += 1;
        if (/[a-z]/.test(pass)) score += 1;
        if (/[0-9]/.test(pass)) score += 1;
        if (/[^A-Za-z0-9]/.test(pass)) score += 1; // Special char bonus
        return Math.min(score, 4);
    };

    const strength = calculateStrength(passwordValue);

    // Map strength score to colors and labels
    const getStrengthColor = (score: number) => {
        if (score === 0) return 'bg-gray-200';
        if (score <= 1) return 'bg-red-500';
        if (score === 2) return 'bg-yellow-500';
        if (score === 3) return 'bg-blue-500';
        return 'bg-green-500';
    };

    const getStrengthLabel = (score: number) => {
        if (score === 0) return '';
        if (score <= 1) return 'Weak';
        if (score === 2) return 'Fair';
        if (score === 3) return 'Good';
        return 'Strong';
    };

    const onSubmit = async (data: RegisterFormInputs) => {
        setIsSubmitting(true);
        try {
            const payload: RegisterRequest = {
                name: data.name,
                email: data.email,
                phone: data.phone,
                password: data.password,
                role: data.role as 'PATIENT' | 'MEDICAL_OFFICER' | 'TECHNICIAN',
                address: data.address,
                dateOfBirth: data.dateOfBirth
            };

            await registerUser(payload);

            // Successfully registered and backend automatically logs them in (via contexts)
            switch (payload.role) {
                case 'PATIENT': navigate('/dashboard/patient', { replace: true }); break;
                case 'MEDICAL_OFFICER': navigate('/dashboard/doctor', { replace: true }); break;
                case 'TECHNICIAN': navigate('/dashboard/technician', { replace: true }); break;
                default: navigate('/login', { replace: true });
            }
        } catch (error) {
            // Auth context toasts the error internally
            console.error(error);
        } finally {
            setIsSubmitting(false);
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-background px-4 sm:px-6 lg:px-8 py-10">
            <div className="max-w-xl w-full space-y-8 bg-white p-8 rounded-xl shadow-lg border border-gray-100">
                <div>
                    <h2 className="mt-2 text-center text-3xl font-extrabold text-slate-900">
                        Create an Account
                    </h2>
                    <p className="mt-2 text-center text-sm text-slate-600">
                        Join Healthcare Lab Test Booking System
                    </p>
                </div>

                <form className="mt-8 space-y-6" onSubmit={handleSubmit(onSubmit)}>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {/* Full Name Field */}
                        <div className="md:col-span-2">
                            <label className="block text-sm font-medium text-slate-700 mb-1">Full Name</label>
                            <div className="relative">
                                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                    <FaUser className="h-4 w-4 text-slate-400" />
                                </div>
                                <input
                                    {...register('name')}
                                    type="text"
                                    className={`block w-full pl-10 pr-3 py-2 border ${errors.name ? 'border-danger focus:ring-danger focus:border-danger' : 'border-gray-300 focus:ring-primary focus:border-primary'} rounded-md shadow-sm sm:text-sm transition-colors duration-200`}
                                    placeholder="John Doe"
                                />
                            </div>
                            {errors.name && <p className="mt-1 text-xs text-danger">{errors.name.message}</p>}
                        </div>

                        {/* Email Field */}
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">Email Address</label>
                            <div className="relative">
                                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                    <FaEnvelope className="h-4 w-4 text-slate-400" />
                                </div>
                                <input
                                    {...register('email')}
                                    type="email"
                                    className={`block w-full pl-10 pr-3 py-2 border ${errors.email ? 'border-danger focus:ring-danger focus:border-danger' : 'border-gray-300 focus:ring-primary focus:border-primary'} rounded-md shadow-sm sm:text-sm transition-colors duration-200`}
                                    placeholder="you@example.com"
                                />
                            </div>
                            {errors.email && <p className="mt-1 text-xs text-danger">{errors.email.message}</p>}
                        </div>

                        {/* Phone Field */}
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">Phone Number</label>
                            <div className="relative">
                                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                    <FaPhone className="h-4 w-4 text-slate-400" />
                                </div>
                                <input
                                    {...register('phone')}
                                    type="text"
                                    className={`block w-full pl-10 pr-3 py-2 border ${errors.phone ? 'border-danger focus:ring-danger focus:border-danger' : 'border-gray-300 focus:ring-primary focus:border-primary'} rounded-md shadow-sm sm:text-sm transition-colors duration-200`}
                                    placeholder="1234567890"
                                />
                            </div>
                            {errors.phone && <p className="mt-1 text-xs text-danger">{errors.phone.message}</p>}
                        </div>

                        {/* Password Field */}
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">Password</label>
                            <div className="relative">
                                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                    <FaLock className="h-4 w-4 text-slate-400" />
                                </div>
                                <input
                                    {...register('password')}
                                    type="password"
                                    className={`block w-full pl-10 pr-3 py-2 border ${errors.password ? 'border-danger focus:ring-danger focus:border-danger' : 'border-gray-300 focus:ring-primary focus:border-primary'} rounded-md shadow-sm sm:text-sm transition-colors duration-200`}
                                    placeholder="ÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇó"
                                />
                            </div>
                            {errors.password && <p className="mt-1 text-xs text-danger">{errors.password.message}</p>}

                            {/* Password Strength Meter */}
                            {passwordValue && (
                                <div className="mt-2">
                                    <div className="flex justify-between items-center mb-1 text-xs">
                                        <span className="text-slate-500">Password strength:</span>
                                        <span className={`font-medium ${strength >= 3 ? 'text-green-600' : strength === 2 ? 'text-yellow-600' : 'text-red-600'}`}>
                                            {getStrengthLabel(strength)}
                                        </span>
                                    </div>
                                    <div className="w-full bg-gray-200 rounded-full h-1.5 flex overflow-hidden">
                                        <div className={`h-full transition-all duration-300 ${getStrengthColor(strength)}`} style={{ width: '25%' }}></div>
                                        <div className={`h-full transition-all duration-300 ${strength >= 2 ? getStrengthColor(strength) : 'bg-transparent'} border-l border-white`} style={{ width: '25%' }}></div>
                                        <div className={`h-full transition-all duration-300 ${strength >= 3 ? getStrengthColor(strength) : 'bg-transparent'} border-l border-white`} style={{ width: '25%' }}></div>
                                        <div className={`h-full transition-all duration-300 ${strength >= 4 ? getStrengthColor(strength) : 'bg-transparent'} border-l border-white`} style={{ width: '25%' }}></div>
                                    </div>
                                </div>
                            )}
                        </div>

                        {/* Confirm Password Field */}
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">Confirm Password</label>
                            <div className="relative">
                                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                    <FaLock className="h-4 w-4 text-slate-400" />
                                </div>
                                <input
                                    {...register('confirmPassword')}
                                    type="password"
                                    className={`block w-full pl-10 pr-3 py-2 border ${errors.confirmPassword ? 'border-danger focus:ring-danger focus:border-danger' : 'border-gray-300 focus:ring-primary focus:border-primary'} rounded-md shadow-sm sm:text-sm transition-colors duration-200`}
                                    placeholder="ÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇó"
                                />
                            </div>
                            {errors.confirmPassword && <p className="mt-1 text-xs text-danger">{errors.confirmPassword.message}</p>}
                        </div>

                        {/* Role Dropdown */}
                        <div className="md:col-span-2">
                            <label className="block text-sm font-medium text-slate-700 mb-1">Account Type</label>
                            <div className="relative">
                                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                    <FaUser className="h-4 w-4 text-slate-400" />
                                </div>
                                <select
                                    {...register('role')}
                                    className="block w-full pl-10 pr-3 py-2 border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-primary focus:border-primary sm:text-sm transition-colors duration-200 cursor-pointer bg-white"
                                >
                                    <option value="PATIENT">Patient</option>
                                    <option value="MEDICAL_OFFICER">Doctor / Medical Officer</option>
                                    <option value="TECHNICIAN">Lab Technician</option>
                                </select>
                            </div>
                            {errors.role && <p className="mt-1 text-xs text-danger">{errors.role.message}</p>}
                        </div>

                        {/* Conditional Patient Fields */}
                        {selectedRole === 'PATIENT' && (
                            <>
                                <div className="md:col-span-2">
                                    <label className="block text-sm font-medium text-slate-700 mb-1">Home Address</label>
                                    <div className="relative">
                                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                            <FaMapMarkerAlt className="h-4 w-4 text-slate-400" />
                                        </div>
                                        <input
                                            {...register('address')}
                                            type="text"
                                            className={`block w-full pl-10 pr-3 py-2 border ${errors.address ? 'border-danger focus:ring-danger focus:border-danger' : 'border-gray-300 focus:ring-primary focus:border-primary'} rounded-md shadow-sm sm:text-sm transition-colors duration-200`}
                                            placeholder="123 Health Ave, City, State ZIP"
                                        />
                                    </div>
                                    {errors.address && <p className="mt-1 text-xs text-danger">{errors.address.message}</p>}
                                </div>

                                <div>
                                    <label className="block text-sm font-medium text-slate-700 mb-1">Date of Birth</label>
                                    <div className="relative">
                                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                            <FaCalendar className="h-4 w-4 text-slate-400" />
                                        </div>
                                        <input
                                            {...register('dateOfBirth')}
                                            type="date"
                                            className={`block w-full pl-10 pr-3 py-2 border ${errors.dateOfBirth ? 'border-danger focus:ring-danger focus:border-danger' : 'border-gray-300 focus:ring-primary focus:border-primary'} rounded-md shadow-sm sm:text-sm transition-colors duration-200`}
                                        />
                                    </div>
                                    {errors.dateOfBirth && <p className="mt-1 text-xs text-danger">{errors.dateOfBirth.message}</p>}
                                </div>
                            </>
                        )}

                    </div>

                    <div>
                        <button
                            type="submit"
                            disabled={isSubmitting}
                            className="group relative w-full flex justify-center py-2.5 px-4 border border-transparent text-sm font-medium rounded-md text-white bg-primary hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary transition-colors duration-200 cursor-pointer disabled:opacity-70 disabled:cursor-not-allowed"
                        >
                            {isSubmitting ? (
                                <div className="flex items-center">
                                    <LoadingSpinner size="sm" />
                                    <span className="ml-2">Creating account...</span>
                                </div>
                            ) : (
                                'Register'
                            )}
                        </button>
                    </div>

                    <div className="text-center mt-4">
                        <span className="text-sm text-slate-600">Already have an account? </span>
                        <Link to="/login" className="text-sm font-medium text-primary hover:text-blue-500 transition-colors duration-200">
                            Sign in here
                        </Link>
                    </div>
                </form>
            </div >
        </div >
    );
};

export default Register;
